{
  "parameters": "z.object({ bowEnabled: z.boolean().describe("Whether to use the bow for attacking").default(true), maxTicks: z.number().describe("Maximum duration of kiting in ticks").default(120), retreatBlocks: z.number().describe("The distance to back away from the target").default(10) })",
  "executionArgs": {
    "bowEnabled": true,
    "maxTicks": 60,
    "retreatBlocks": 10
  },
  "code": "const sleep = function (ms) {
  return new Promise(function (resolve) { setTimeout(resolve, ms); });
};
const getNearestHostile = function () {
  const hostiles = Object.values(bot.entities).filter(function (e) {
    return (e.type === 'mob' || e.type === 'hostile') && e.kind === 'Hostile mobs' && e.health > 0;
  });
  hostiles.sort(function (a, b) {
    return bot.entity.position.distanceTo(a.position) - bot.entity.position.distanceTo(b.position);
  });
  return hostiles[0];
};
const target = getNearestHostile();
if (!target) {
  return "<NO TARGET>: No nearby hostile mobs found to kite.";
}
const bow = bot.inventory.items().find(function (item) {
  return item.name === 'bow';
});
const arrows = bot.inventory.items().find(function (item) {
  return item.name === 'arrow';
});
if (args.bowEnabled && (!bow || !arrows)) {
  return "<NO AMMO>: Bow or arrows missing from inventory.";
}
startBackgroundSkill(bot, 'kite_and_retreat', async function (token) {
  let ticks = 0;
  const movements = new Movements(bot);
  movements.allowSprinting = true;
  bot.pathfinder.setMovements(movements);
  while (!token.cancelled && bot.health > 0 && Boolean(bot.entity) && ticks < args.maxTicks) {
    const currentTarget = getNearestHostile();
    if (!currentTarget) break;
    if (!bot.physicsEnabled) {
      await sleep(50);
      continue;
    }
    const diff = bot.entity.position.subtract(currentTarget.position);
    const retreatDir = diff.normalize().scale(args.retreatBlocks);
    const retreatGoal = bot.entity.position.plus(retreatDir);
    bot.pathfinder.setGoal(new goals.GoalNear(retreatGoal.x, retreatGoal.y, retreatGoal.z, 1));
    if (args.bowEnabled && bow) {
      await bot.equip(bow, 'hand');
      bot.lookAt(currentTarget.position.offset(0, 1.6, 0));
      if (ticks % 20 === 0) {
        bot.activateItem();
        await sleep(1000);
        bot.deactivateItem();
      }
    }
    await sleep(50);
    ticks++;
  }
  bot.pathfinder.setGoal(null);
});
return "<KITING>: Attempting to retreat from " + target.name + " while using bow.";"
}
